/// <summary>
/// Extension class for LedgerJournalFormTrans Class
/// </summary>
[ExtensionOf(classStr(LedgerJournalFormTrans))]
public final class ETGLedgerJournalFormTrans_Extension
{
    private FormFunctionButtonControl   ctrlETGAccrualButton;

}

Method.Source:
public void enableButtonsActive()
{
    next enableButtonsActive();

    this.setETGAccrualButtonEnabled();
}

public FormFunctionButtonControl parmCtrlETGAccrualButton(FormFunctionButtonControl _ctrlETGAccrualButton = ctrlAccrualButton)
{
    ctrlETGAccrualButton = _ctrlETGAccrualButton;

    return ctrlETGAccrualButton;
}

/// <summary>
///    Enables or disables the accrual button of the lines form.
/// </summary>
protected void setETGAccrualButtonEnabled()
{
    boolean enabled;

    if (ctrlETGAccrualButton)
    {
        enabled = this.isJournalEnabled() && ledgerJournalTrans.Company == curext();

        if (isActiveWFApprovalDocument)
        {
            enabled = enabled && isUIElementWFApprovalEnabled;
        }

        ctrlETGAccrualButton.enabled(enabled);
    }
}
